// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007LL
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N; int M;
        scanf("%lld %d", &N, &M);
        long long ans = 1;
        for (int i = 0; i < M; ++i) {
            int op; long long u, v;
            scanf("%d %lld %lld", &op, &u, &v);
            if (op == 0) {
                ans = (ans * (v - u + 1)) % MOD;
            } else { // op == 1
                ans = (ans * 2) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

